        case .Cache(_ /* message is ignored*/):
            writeInt(&buf, Int32(7))
        case .NotFound(_ /* message is ignored*/):
            writeInt(&buf, Int32(8))
        case .Other(_ /* message is ignored*/):
            writeInt(&buf, Int32(9))

        
        }
